import Foundation

enum APIEnvironment {
    case development, staging, production
}

struct Constants {
    static let baseURL = "https://api.example.com"
}

struct APIClient {
    private let session: URLSession
    private let environment: APIEnvironment

    init(environment: APIEnvironment) {
        self.environment = environment
        self.session = URLSession(configuration: defaultConfiguration())
    }

    private func defaultConfiguration() -> URLSessionConfiguration {
        let configuration = URLSessionConfiguration.default
        configuration.httpAdditionalHeaders = ["Accept": "application/json"]

        switch environment {
        case .development:
            configuration.urlCredentials = URLCredential(user: "devUsername", password: "devPassword", persistence: .forSession)
        case .staging, .production:
            // Add authentication credentials for staging and production environments if needed
            break
        }

        return configuration
    }

    func get(from url: URL, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) {
        let task = session.dataTask(with: url) { data, response, error in
            DispatchQueue.main.async {
                completionHandler(data, response, error)
            }
        }
        task.resume()
    }

    func post(to url: URL, with parameters: [String: Any], completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) {
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        do {
            let jsonData = try JSONSerialization.data(withJSONObject: parameters, options: .prettyPrinted)
            request.httpBody = jsonData
        } catch {
            print("Error serializing JSON:", error)
            completionHandler(nil, nil, error)
            return
        }

        let task = session.dataTask(with: request) { data, response, error in
            DispatchQueue.main.async {
                completionHandler(data, response, error)
            }
        }
        task.resume()
    }
}